module RefModule(clk, rst, D, Q);
    input clk;
    input rst;
    input [3:0] D;
    output reg [3:0] Q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst) begin
            Q <= 4'b0000;
        end else begin
            Q <= D;
        end
    end
endmodule
